const d = $json.body ?? $json;

const fAppName      = String(d.appName      || '錢錢管家');
const fAppVersion   = String(d.appVersion   || '?');
const fCategory     = String(d.category     || 'General');
const fMsg          = String(d.message      || '');
const fEmail        = String(d.contactEmail || '');
const fPlatform     = String(d.platform     || '');
const fOsVersion    = String(d.osVersion    || '');
const fDeviceModel  = String(d.deviceModel  || '');
const fSourcePage   = String(d.sourcePage   || '');
const fHasImages    = String(d.hasImages    || 'false');
const fCreatedAt    = String(d.createdAt    || new Date().toISOString());

const subject = '[' + fAppName + ' Feedback] ' + fCategory + ' — v' + fAppVersion;

const body = '=== ' + fAppName + ' User Feedback ===\n\n'
  + '類別:    ' + fCategory + '\n'
  + '訊息:\n' + fMsg + '\n\n'
  + '聯絡信箱: ' + (fEmail || '未提供') + '\n'
  + 'App 版本: ' + fAppName + ' v' + fAppVersion + '\n'
  + '平台:    ' + fPlatform + ' ' + fOsVersion + '\n'
  + '裝置:    ' + fDeviceModel + '\n'
  + '來源頁面: ' + fSourcePage + '\n'
  + '附圖:    ' + (fHasImages === 'true' ? 'Yes' : 'No') + '\n'
  + '時間:    ' + fCreatedAt + '\n'
  + '\n--- DEBUG ---\n'
  + JSON.stringify(d);

return [{ json: { emailSubject: subject, emailBody: body } }];
